Langsung saja. Modul autentikasi adalah target utama serangan (Brute-force, SQLi, Credential Stuffing). Test suite tidak boleh hanya mengecek fungsi "login berhasil", tapi harus memvalidasi keamanan implementasinya.

Berikut adalah struktur test suite menggunakan `pytest` dengan fokus pada defensive security.

### 1. Dependensi
Install library yang diperlukan untuk hashing dan testing:
```bash
pip install pytest bcrypt python-jose
```

### 2. Mock Module (`auth.py`)
Ini adalah modul sederhana yang akan kita test. Pastikan produksi Anda menggunakan pattern serupa (hashed password, parameterized query).

```python
# auth.py
import bcrypt
import jwt
from datetime import datetime, timedelta

SECRET_KEY = "super_secret_key_change_in_prod"
ALGORITHM = "HS256"

class AuthModule:
    def __init__(self, db_connection):
        self.db = db_connection

    def hash_password(self, password: str) -> str:
        return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

    def verify_password(self, password: str, hashed: str) -> bool:
        return bcrypt.checkpw(password.encode('utf-8'), hashed.encode('utf-8'))

    def login(self, username: str, password: str) -> dict:
        # Simulasi query aman (parameterized)
        user = self.db.get_user(username) 
        if not user or not self.verify_password(password, user['password']):
            raise ValueError("Invalid credentials")

        return self.create_token(user['id'])

    def create_token(self, user_id: int) -> dict:
        expire = datetime.utcnow() + timedelta(minutes=30)
        token = jwt.encode({"sub": user_id, "exp": expire}, SECRET_KEY, algorithm=ALGORITHM)
        return {"access_token": token, "token_type": "bearer"}
```

### 3. Test Suite (`test_auth.py`)
Fokus pada validasi keamanan, edge cases, dan integritas data.

```python
# test_auth.py
import pytest
import bcrypt
import jwt
from auth import AuthModule, SECRET_KEY, ALGORITHM
from datetime import datetime, timedelta

# Mock Database Class untuk testing
class MockDB:
    def __init__(self, users=None):
        self.users = users or {}

    def get_user(self, username):
        return self.users.get(username)

@pytest.fixture
def auth_module():
    return AuthModule(MockDB())

@pytest.fixture
def valid_user():
    password = "SecurePass123!"
    hashed = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
    return {"username": "admin", "password": password, "hashed": hashed, "id": 1}

class TestAuthenticationSecurity:

    def test_password_hashing_not_plain_text(self, auth_module, valid_user):
        """Pastikan password tidak disimpan dalam plain text."""
        hashed = auth_module.hash_password(valid_user['password'])
        assert hashed != valid_user['password']
        assert hashed.startswith('$2b$') # Verifikasi bcrypt prefix

    def test_login_success(self, auth_module, valid_user):
        """Test alur login normal."""
        auth_module.db.users = {valid_user['username']: {'password': valid_user['hashed'], 'id': valid_user['id']}}
        result = auth_module.login(valid_user['username'], valid_user['password'])
        assert "access_token" in result

    def test_login_failed_wrong_password(self, auth_module, valid_user):
        """Test penanganan gagal login untuk mencegah info leakage."""
        auth_module.db.users = {valid_user['username']: {'password': valid_user['hashed'], 'id': valid_user['id']}}
        with pytest.raises(ValueError) as exc_info:
            auth_module.login(valid_user['username'], "WrongPassword")
        assert str(exc_info.value) == "Invalid credentials"

    def test_login_failed_sql_injection_attempt(self, auth_module):
        """Test ketahanan terhadap input SQL Injection dasar."""
        malicious_user = "' OR '1'='1"
        # Harus raise error atau return None, tidak boleh crash atau bypass
        with pytest.raises(Exception):
            # Asumsi implementasi db.get_user aman, jika tidak, test ini akan fail
            auth_module.login(malicious_user, "anything")

    def test_token_expiration(self, auth_module, valid_user):
        """Validasi token memiliki expiry time."""
        auth_module.db.users = {valid_user['username']: {'password': valid_user['hashed'], 'id': valid_user['id']}}
        result = auth_module.login(valid_user['username'], valid_user['password'])
        token = result['access_token']

        decoded = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        assert "exp" in decoded

        # Cek apakah exp adalah waktu di masa depan
        assert decoded['exp'] > datetime.utcnow().timestamp()

    def test_constant_time_comparison(self, auth_module, valid_user):
        """Pastikan verifikasi password menggunakan constant-time comparison (bcrypt sudah handle ini)."""
        # Ini lebih ke validasi library, tapi penting dicatat
        assert bcrypt.checkpw(b"test", bcrypt.hashpw(b"test", bcrypt.gensalt()))

    def test_rate_limiting_logic(self, auth_module, valid_user):
        """Simulasi test logika rate limiting (harus ada di layer controller)."""
        # Contoh assert untuk memastikan counter ada
        auth_module.db.users = {valid_user['username']: {'password': valid_user['hashed'], 'id': valid_user['id']}}

        # Coba login gagal 5 kali
        for _ in range(5):
            with pytest.raises(ValueError):
                auth_module.login(valid_user['username'], "wrong")

        # Di produksi, percobaan ke-6 seharusnya diblokir sementara
        # Implementasi ini tergantung pada middleware, tapi logika harus diuji
        # assert auth_module.db.is_locked(valid_user['username']) == True
```

### 4. Catatan Keamanan (Security Notes)

1.  **Information Leakage:** Perhatikan pesan error. Jangan pernah mengembalikan "User not found" vs "Wrong password". Gunakan pesan generik "Invalid credentials" untuk mencegah enumerasi user.
2.  **Timing Attacks:** `bcrypt.checkpw` sudah menggunakan constant-time comparison. Jangan implementasi verifikasi password manual menggunakan `==` pada string hash.
3.  **Token Security:** Pastikan `SECRET_KEY` tidak hardcode di production (gunakan Environment Variables). Validasi algoritma JWT saat decode untuk mencegah serangan "None Algorithm".
4.  **Rate Limiting:** Test suite di atas hanya mocking. Di produksi, pastikan ada middleware (Redis/Nginx) yang membatasi request login per IP/User.

Jalankan test dengan verbose mode untuk melihat detail kegagalan:
```bash
pytest test_auth.py -v
```

Pastikan coverage minimal 90% untuk modul kritis seperti ini.
